import React from 'react';
import { Button, Alert } from 'react-native';
import FaceNet from './native/FaceNet';
import { dummyEmployeeList } from './utils/dummy';

export default function App() {
  const onInit = async () => {
    // Example: employees array from your API
    // Each employee must include `image` as base64 string
    const employees = [
      {
        id: 1,
        name: 'Jerald',
        imageUrl:
          'https://media.assettype.com/tnm%2Fimport%2Fsites%2Fdefault%2Ffiles%2FManikandan_171121_3_1200.jpg?w=1024&auto=format%2Ccompress&fit=max',
        // image:
        //   'data:image/jpeg;base64,',
      },
      // {
      //   id: 2,
      //   name: 'Vijay Devor',
      //   image:
      //     'data:image/jpeg;base64,',
      // },
      // {
      //   id: 3,
      //   name: 'VIJAY',
      //   image:
      //     'data:image/webp;base64,',
      // },
      // {
      //   id: 4,
      //   name: 'VIJAYKANTH',
      //   image:
      //     'data:image/jpeg;base64,',
      // },
      // {
      //   id: 5,
      //   name: 'SURIYA',
      //   image:
      //     'data:image/jpeg;base64,',
      // },
      // {
      //   id: 6,
      //   name: 'DHANUSH',
      //   image:
      //     'data:image/webp;base64,',
      // },
      // {
      //   id: 8,
      //   name: 'JAYAM RAVI',
      //   image:
      //     'data:image/jpeg;base64,',
      // },
      // ... potentially large list
    ];
    const employees1 = Array.from({ length: 50 }, (_, index) => {
      const emp =
        dummyEmployeeList[Math.floor(Math.random() * dummyEmployeeList.length)];

      return {
        id: index,
        name: emp.name,
        imageUrl: emp.imageUrl,
      };
    });

    console.log('employees1:', employees1);
    try {
      await FaceNet.initializeEmployees(employees1);
      console.log('FINIESH');
      Alert.alert('Init done');
    } catch (e) {
      Alert.alert('Init error', e.message || e.toString());
    }
  };

  const onCompare = async () => {
    // capture base64 for camera image elsewhere
    const capturedBase64 =
      'data:image/jpeg;base64,';

    try {
      console.log('START');
      const matches = await FaceNet.compareCapturedFace(capturedBase64, 10);
      console.log('END');

      // matches is array [{id, name, score}, ...] already sorted desc by score
      // JS decide:
      if (matches && matches.length > 0 && matches[0].score >= 0.6) {
        Alert.alert(
          'Auto matched',
          `${matches[0].name} (${matches[0].id}) score:${matches[0].score}`,
        );
      } else {
        Alert.alert('Top matches', JSON.stringify(matches));
      }
    } catch (e) {
      Alert.alert('Compare error', e.message || e.toString());
    }
  };

  return (
    <>
      <Button title="Initialize Employees" onPress={onInit} />
      <Button title="Compare Now" onPress={onCompare} />
    </>
  );
}
